import{_ as i,c as a,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const g=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/阅读工具/legado-阅读工具.md","filePath":"github汇总/阅读工具/legado-阅读工具.md"}'),o={name:"github汇总/阅读工具/legado-阅读工具.md"};function t(h,l,n,s,d,p){return e(),a("div",null,l[0]||(l[0]=[r('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>阅读3.0 (legado)</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>gedoor</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>阅读工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>用户需要一个功能丰富、无广告、支持自定义书源的阅读应用。</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><p>开源阅读应用，支持自定义书源、本地阅读、高度自定义阅读界面等功能。</p><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>自定义书源：支持自己设置规则，抓取网页数据</li><li>书架模式：列表和网格书架自由切换</li><li>书源搜索：支持搜索及发现功能</li><li>内容订阅：可以订阅想看的任何内容</li><li>替换净化：去除广告替换内容</li><li>本地阅读：支持TXT、EPUB格式</li><li>高度自定义：字体、颜色、背景、行距等</li><li>多种翻页模式：覆盖、仿真、滑动、滚动等</li><li>开源无广告：持续优化，无广告</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/gedoor/legado" target="_blank" rel="noreferrer">https://github.com/gedoor/legado</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于喜欢阅读的用户，需要一个功能丰富、无广告的阅读应用。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li>Android设备</li><li>允许安装来自未知来源的应用</li></ol><h2 id="主路径-安装与使用" tabindex="-1">主路径：安装与使用 <a class="header-anchor" href="#主路径-安装与使用" aria-label="Permalink to “主路径：安装与使用”">​</a></h2><ol><li><p><strong>下载安装包</strong></p><ul><li>目标：下载阅读3.0的APK安装包</li><li>位置：GitHub Releases页面</li><li>命令：访问<a href="https://github.com/gedoor/legado/releases%E4%B8%8B%E8%BD%BD%E6%9C%80%E6%96%B0%E7%89%88%E6%9C%AC%E7%9A%84APK" target="_blank" rel="noreferrer">https://github.com/gedoor/legado/releases下载最新版本的APK</a></li><li>成功标志：下载完成</li><li>失败处理：检查网络连接，确保GitHub可以访问</li></ul></li><li><p><strong>安装应用</strong></p><ul><li>目标：安装阅读3.0应用</li><li>位置：Android设备</li><li>命令：打开下载的APK文件，按照提示安装</li><li>成功标志：应用安装完成，图标出现在桌面</li><li>失败处理：检查设备是否允许安装来自未知来源的应用</li></ul></li><li><p><strong>添加书源</strong></p><ul><li>目标：添加自定义书源</li><li>位置：应用内</li><li>命令：打开应用 → 书源管理 → 右上角添加 → 输入书源规则</li><li>成功标志：书源添加成功，可在书源列表中看到</li><li>失败处理：检查书源规则格式是否正确</li></ul></li><li><p><strong>导入书籍</strong></p><ul><li>目标：导入书籍到书架</li><li>位置：应用内</li><li>命令： <ul><li>在线书籍：书源搜索 → 选择书籍 → 加入书架</li><li>本地书籍：本地书籍 → 扫描 → 选择书籍 → 加入书架</li></ul></li><li>成功标志：书籍出现在书架中</li><li>失败处理：检查书源是否正常，本地书籍路径是否正确</li></ul></li><li><p><strong>自定义阅读设置</strong></p><ul><li>目标：自定义阅读界面</li><li>位置：应用内</li><li>命令：打开书籍 → 点击屏幕中央 → 右下角设置 → 调整字体、颜色、背景等</li><li>成功标志：阅读界面按照设置显示</li><li>失败处理：检查设置是否保存成功</li></ul></li></ol><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><ul><li>访问地址：应用图标</li><li>检查命令：打开应用，添加书源，导入书籍</li><li>预期返回：应用正常运行，书籍可正常阅读</li></ul><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>书源添加失败</strong></p><ul><li>现象：书源添加后无法使用</li><li>可能原因：书源规则格式错误，或网站结构变化</li><li>解决步骤：检查书源规则，更新规则以适应网站变化</li></ul></li><li><p><strong>本地书籍扫描失败</strong></p><ul><li>现象：本地书籍无法扫描到</li><li>可能原因：文件路径权限问题，或文件格式不支持</li><li>解决步骤：检查存储权限，确保文件格式为TXT或EPUB</li></ul></li><li><p><strong>阅读界面设置不生效</strong></p><ul><li>现象：调整阅读设置后界面无变化</li><li>可能原因：设置未保存，或应用缓存问题</li><li>解决步骤：重新调整设置并保存，或清除应用缓存</li></ul></li><li><p><strong>应用崩溃</strong></p><ul><li>现象：应用启动或使用过程中崩溃</li><li>可能原因：设备系统版本不兼容，或应用版本问题</li><li>解决步骤：更新应用到最新版本，或检查设备系统版本</li></ul></li></ol><h2 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h2><ul><li><strong>F-Droid</strong>：通过F-Droid应用商店安装</li><li><strong>源码构建</strong>：克隆仓库，自行构建APK</li></ul><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>README/仓库信息中提供了基本的功能介绍，详细使用指南可参考官方帮助文档。</p>',31)]))}const b=i(o,[["render",t]]);export{g as __pageData,b as default};
